    result = subprocess.run(
        [\"ffmpeg\", \"-i\", frame_path, \"-f\", \"rawvideo\", \"-pix_fmt\", \"rgb24\", \"-vframes\", \"1\", \"pipe:1\"],
        capture_output=True
    )
    return result.stdout

def analyze_frame(frame_path, frame_num):
    \"\"\"Analyze a frame for chapter card characteristics\"\"\"
