    if not raw:
        return None
    # Assume 1280x720 or similar - let's figure out dimensions
    # Try common resolutions
    for w, h in [(1280, 720), (1920, 1080), (854, 480), (640, 360)]:
        if len(raw) == w * h * 3:
            pixels = np.frombuffer(raw, dtype=np.uint8).reshape(h, w, 3)
