import subprocess
import numpy as np
import os

def get_frame_pixels(frame_path):
    result = subprocess.run(
        [\"ffmpeg\", \"-i\", frame_path, \"-f\", \"rawvideo\", \"-pix_fmt\", \"rgb24\", \"-vframes\", \"1\", \"pipe:1\"],
        capture_output=True
    )
    raw = result.stdout
    if len(raw) == 640 * 360 * 3:
        return np.frombuffer(raw, dtype=np.uint8).reshape(360, 640, 3)
    return None

# Scan all frames and compute stats to find chapter cards
frames_dir = \"/tmp/frames\"
frame_files = sorted(os.listdir(frames_dir))

stats = []
for fname in frame_files:
    frame_num = int(fname.replace(\"frame_\", \"\").replace(\".jpg\", \"\"))
    timestamp = (frame_num - 1) * 2  # 0.5fps = 1 frame per 2 seconds
    path = os.path.join(frames_dir, fname)
    pixels = get_frame_pixels(path)
    if pixels is not None:
        mean_brightness = pixels.mean()
        std_brightness = pixels.std()
        # Check if mostly dark (potential title card)
        dark_ratio = (pixels < 30).mean()
        # Check if mostly uniform color
        stats.append((frame_num, timestamp, mean_brightness, std_brightness, dark_ratio))

# Print frames that might be title cards (dark background)
print(\"Frames with dark backgrounds (potential title cards):\")
for frame_num, ts, mean_b, std_b, dark_r in stats:
    if dark_r > 0.3:  # More than 30% dark pixels
        print(f\"  Frame {frame_num:4d} (t={ts:5d}s): mean={mean_b:.1f}, std={std_b:.1f}, dark_ratio={dark_r:.3f}\")
